"use strict";(self.webpackChunkTartaria=self.webpackChunkTartaria||[]).push([[973],{7950:(i,l,e)=>{e.r(l),e.d(l,{data:()=>a});const a={key:"v-8a88ed16",path:"/wisdom/",title:"Забытые пословицы и поговорки",lang:"ru-RU",frontmatter:{sidebarDepth:2},excerpt:"",headers:[],filePathRelative:"wisdom/README.md",git:{updatedTime:1705765057e3,contributors:[{name:"blackchestnut",email:"alexander.kalinichev@gmail.com",commits:6}]}}},3441:(i,l,e)=>{e.r(l),e.d(l,{default:()=>r});const a=(0,e(6252).uE)('<h1 id="забытые-пословицы-и-поговорки" tabindex="-1"><a class="header-anchor" href="#забытые-пословицы-и-поговорки" aria-hidden="true">#</a> Забытые пословицы и поговорки</h1><ul><li>Бабушка гадала, надвое сказала: то ли дождик, то ли снег, то ли будет, то ли нет</li><li>Бедность — не порок, а большое несчастье</li><li>В здоровом теле здоровый дух — редкая удача</li><li>Везет как субботнему утопленнику — баню топить не надо</li><li>Ворон ворону глаз не выклюет, а и выклюет, да не вытащит</li><li>В шалаше, да по душе, а в хоромах, как на похоронах</li><li>Гладко было на бумаге, да забыли про овраги, а по ним ходить</li><li>Гол как сокол, а остер как топор</li><li>Губа не дура, язык не лопатка, знает, где кисло, знает, где сладко</li><li>Два сапога пара, оба левые</li><li>Девичий стыд — до порога, переступила и забыла</li><li>Дорога ложка к обеду, а там хоть под лавку</li><li>Дуракам закон не писан, если писан — то не читан, если читан — то не понят, если понят — то не так</li><li>Дураку хоть кол теши, он своих два ставит</li><li>За битого двух небитых дают, да не больно-то берут</li><li>За двумя зайцами погонишься — ни одного кабана не поймаешь</li><li>Зайца ноги носят, волка зубы кормят, лису хвост бережет</li><li>И делу время, и потехе час</li><li>Комар лошадь не повалит, пока медведь не подсобит</li><li>Кто старое помянет — тому глаз вон, а кто забудет — тому оба</li><li>Курочка по зернышку клюет, а весь двор в помёте</li><li>Лиха беда начало — есть дыра, будет и прореха</li><li>Молодые бранятся — тешатся, а старики бранятся — бесятся</li><li>На сердитых воду возят, а на добрых сами катаются</li><li>На чужой каравай рот не разевай, пораньше вставай да свой затевай</li><li>Не все коту масленица, будет и пост</li><li>Не печалится дятел, что петь не может, его и так весь лес слышит</li><li>Ни рыба, ни мясо, ни кафтан, ни ряса</li><li>Нужда и стужа - нет вас хуже <em>/ Стужа да нужа - нет того хуже</em></li><li>Новая метла по-новому метёт, а как сломается — под лавкой валяется</li><li>Один в поле не воин, а путник</li><li>От работы кони дохнут, а люди — крепнут</li><li>Палка о двух концах, туда и сюда бьет</li><li>Повторенье — мать ученья, утешенье дураков</li><li>Пыль столбом, дым коромыслом, а изба не топлена, не метена</li><li>Пьяному море по колено, а лужа — по уши</li><li>Работа — не волк, в лес не убежит, потому её, окаянную, делать и надо</li><li>Расти большой, да не будь лапшой, тянись верстой, да не будь простой</li><li>Рука руку моет, да обе свербят</li><li>Рыбак рыбака видит издалека, потому стороной и обходит</li><li>С пчелой поладишь — медку достанешь, с жуком свяжешься — в навозе окажешься</li><li>Собака на сене лежит, сама не ест и скотине не дает</li><li>Собаку съели, хвостом подавились</li><li>Старость не радость, сядешь — не встанешь, побежишь — не остановишься</li><li>Старый конь борозды не испортит, да и глубоко не вспашет</li><li>Тише едешь — дальше будешь от того места, куда едешь</li><li>У страха глаза велики, да ничего не видят</li><li>Ума палата, да ключ потерян</li><li>Хлеб на стол — и стол престол, а хлеба ни куска — и стол доска</li><li>Чем черт не шутит пока Бог спит</li><li>Что лето запасет - Зима все подберет</li><li>Чудеса в решете — дыр много, а выскочить некуда</li><li>Шито-крыто, а узелок-то тут</li><li>Язык мой — враг мой, прежде ума рыщет, беды ищет</li></ul>',2),t={},r=(0,e(3744).Z)(t,[["render",function(i,l){return a}]])},3744:(i,l)=>{l.Z=(i,l)=>{for(const[e,a]of l)i[e]=a;return i}}}]);